#include <unordered_map>
#include <vector>

using namespace std;

long long solve(vector<vector<long long>> points) {
    const long long MOD = 1e9 + 7;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 1e9+7

    unordered_map<long long, long long> y_counts;
    for (auto& p : points) {
        y_counts[p[1]]++;
    }

    long long S = 0;
    long long sum_sq = 0;

    for (auto& [y, cnt] : y_counts) {
        long long term = cnt * (cnt - 1) % MOD;
        term = term * inv2 % MOD;
        S = (S + term) % MOD;

        long long term_sq = term * term % MOD;
        sum_sq = (sum_sq + term_sq) % MOD;
    }

    long long temp = (S * S - sum_sq) % MOD;
    if (temp < 0) temp += MOD;
    long long ans = temp * inv2 % MOD;
    return ans;
}
